int main() {
  int T, N, K, i, j, dist[N + 1];
  char S[N + 1][N + 1];
  scanf("%d", &T);
  while (T--) {
    scanf("%d %d", &N, &K);
    for (i = 1; i <= N; i++)
      scanf("%s", S[i] + 1);
    for (i = 1; i <= N; i++)
      dist[i] = N + 1;
    dist[1] = 0;
    for (i = 1; i <= N; i++)
      for (j = 1; j <= N; j++)
        if (abs(i - j) <= K && S[j][i] == '1')
          dist[j] = min(dist[j], dist[i] + 1);
    printf("%d\n", dist[N] > N ? -1 : dist[N]);
  }
  return 0;
}

