public class Main {
  public static void main(String[] args) {
    Scanner scanner = new Scanner(System.in);
    int T = scanner.nextInt();
    while (T-- > 0) {
      int N = scanner.nextInt();
      int K = scanner.nextInt();
      char[][] S = new char[N + 1][N + 1];
      for (int i = 1; i <= N; i++)
        S[i] = scanner.next().toCharArray();
      int[] dist = new int[N + 1];
      for (int i = 1; i <= N; i++)
        dist[i] = N + 1;
      dist[1] = 0;
      for (int i = 1; i <= N; i++)
        for (int j = 1; j <= N; j++)
          if (Math.abs(i - j) <= K && S[j][i] == '1')
            dist[j] = Math.min(dist[j], dist[i] + 1);
      System.out.println(dist[N] > N ? -1 : dist[N]);
    }
  }
}

