const readline = require('readline').createInterface({ input: process.stdin, output: process.stdout });
let T;
readline.question('', (input) => {
  T = parseInt(input);
  let N, K, i, j, dist = new Array(N + 1).fill(N + 1);
  dist[1] = 0;
  for (let t = 0; t < T; t++) {
    readline.question('', (input) => {
      [N, K] = input.split(' ').map(Number);
      let S = new Array(N + 1);
      for (i = 1; i <= N; i++)
        readline.question('', (input) => {
          S[i] = input.trim().split('');
          for (j = 1; j <= N; j++)
            if (Math.abs(i - j) <= K && S[j][i - 1] === '1')
              dist[j] = Math.min(dist[j], dist[i] + 1);
          readline.question('', (input) => {
            console.log(dist[N] > N ? -1 : dist[N]);
          });
        });
    });
  }
})
